import React, { useState, useEffect } from 'react';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const AdminDashboard = () => {
    const { user } = useAuth();
    const [rides, setRides] = useState([]);
    const [drivers, setDrivers] = useState([]);
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [newRide, setNewRide] = useState({
        routeName: '',
        pickupLocation: { type: 'Point', coordinates: [0, 0], address: '' },
        dropLocation: { type: 'Point', coordinates: [0, 0], address: '' },
        departureTime: '',
        baseFare: '',
        availableSeats: 4
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [ridesRes, driversRes, usersRes] = await Promise.all([
                api.get('/rides'),
                api.get('/users?role=driver'),
                api.get('/users?role=user')
            ]);
            setRides(ridesRes.data.data);
            setDrivers(driversRes.data.data || []);
            setUsers(usersRes.data.data || []);
        } catch (error) {
            toast.error('Failed to fetch data');
        } finally {
            setLoading(false);
        }
    };

    const handleCreateRide = async (e) => {
        e.preventDefault();
        try {
            await api.post('/rides', {
                ...newRide,
                departureTime: new Date(newRide.departureTime)
            });
            toast.success('Ride created successfully!');
            setShowCreateModal(false);
            fetchData();
            setNewRide({
                routeName: '',
                pickupLocation: { type: 'Point', coordinates: [0, 0], address: '' },
                dropLocation: { type: 'Point', coordinates: [0, 0], address: '' },
                departureTime: '',
                baseFare: '',
                availableSeats: 4
            });
        } catch (error) {
            toast.error('Failed to create ride');
        }
    };

    const handleAssignDriver = async (rideId, driverId) => {
        try {
            await api.put(`/rides/${rideId}/assign-driver`, { driverId });
            toast.success('Driver assigned successfully!');
            fetchData();
        } catch (error) {
            toast.error('Failed to assign driver');
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-64">
                <div className="spinner"></div>
            </div>
        );
    }

    return (
        <div className="dashboard-container">
            <div className="dashboard-header flex justify-between items-center">
                <div>
                    <h1 className="dashboard-title">Admin Dashboard</h1>
                    <p className="dashboard-subtitle">Manage rides, drivers, and users</p>
                </div>
                <button
                    onClick={() => setShowCreateModal(true)}
                    className="btn-primary px-6 py-2 rounded-lg"
                >
                    + Create New Ride
                </button>
            </div>

            {/* Stats Section */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
                <div className="stats-card">
                    <div className="stats-number">{rides.length}</div>
                    <div className="stats-label">Total Rides</div>
                </div>
                <div className="stats-card">
                    <div className="stats-number">{drivers.length}</div>
                    <div className="stats-label">Active Drivers</div>
                </div>
                <div className="stats-card">
                    <div className="stats-number">{users.length}</div>
                    <div className="stats-label">Total Users</div>
                </div>
                <div className="stats-card">
                    <div className="stats-number">
                        {rides.filter(r => r.status === 'scheduled').length}
                    </div>
                    <div className="stats-label">Upcoming Rides</div>
                </div>
            </div>

            {/* Rides Management */}
            <div className="mb-8">
                <h2 className="text-2xl font-semibold mb-4">Manage Rides</h2>
                <div className="space-y-4">
                    {rides.map((ride) => (
                        <div key={ride._id} className="card fade-in">
                            <div className="card-body">
                                <div className="flex justify-between items-start">
                                    <div className="flex-1">
                                        <h3 className="text-lg font-semibold">{ride.routeName}</h3>
                                        <p className="text-sm text-gray-500">
                                            {new Date(ride.departureTime).toLocaleString()}
                                        </p>
                                        <div className="mt-2 grid grid-cols-2 gap-2 text-sm">
                                            <p><span className="font-medium">Pickup:</span> {ride.pickupLocation?.address}</p>
                                            <p><span className="font-medium">Drop:</span> {ride.dropLocation?.address}</p>
                                            <p><span className="font-medium">Fare:</span> ₹{ride.baseFare}</p>
                                            <p><span className="font-medium">Seats:</span> {ride.availableSeats}</p>
                                        </div>
                                        <div className="mt-2">
                                            <span className={`badge ${
                                                ride.status === 'scheduled' ? 'badge-warning' :
                                                ride.status === 'active' ? 'badge-success' :
                                                'badge-info'
                                            }`}>
                                                {ride.status}
                                            </span>
                                        </div>
                                    </div>
                                    <div className="ml-4">
                                        <select
                                            onChange={(e) => handleAssignDriver(ride._id, e.target.value)}
                                            value={ride.assignedDriver?._id || ''}
                                            className="form-input text-sm"
                                        >
                                            <option value="">Assign Driver</option>
                                            {drivers.map(driver => (
                                                <option key={driver._id} value={driver._id}>
                                                    {driver.name} - {driver.vehicleDetails?.vehicleNumber || 'No vehicle'}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                    {rides.length === 0 && (
                        <div className="text-center py-8 text-gray-500">
                            <p>No rides created yet. Click "Create New Ride" to get started.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Create Ride Modal */}
            {showCreateModal && (
                <div className="modal-overlay" onClick={() => setShowCreateModal(false)}>
                    <div className="modal-content p-6 max-w-2xl w-full" onClick={(e) => e.stopPropagation()}>
                        <h3 className="text-xl font-bold mb-4">Create New Ride</h3>
                        <form onSubmit={handleCreateRide}>
                            <div className="space-y-4">
                                <div>
                                    <label className="form-label">Route Name</label>
                                    <input
                                        type="text"
                                        required
                                        className="form-input"
                                        value={newRide.routeName}
                                        onChange={(e) => setNewRide({...newRide, routeName: e.target.value})}
                                        placeholder="e.g., Downtown to Tech Park"
                                    />
                                </div>
                                <div>
                                    <label className="form-label">Pickup Address</label>
                                    <input
                                        type="text"
                                        required
                                        className="form-input"
                                        value={newRide.pickupLocation.address}
                                        onChange={(e) => setNewRide({
                                            ...newRide,
                                            pickupLocation: {...newRide.pickupLocation, address: e.target.value}
                                        })}
                                        placeholder="Enter pickup location"
                                    />
                                </div>
                                <div>
                                    <label className="form-label">Drop Address</label>
                                    <input
                                        type="text"
                                        required
                                        className="form-input"
                                        value={newRide.dropLocation.address}
                                        onChange={(e) => setNewRide({
                                            ...newRide,
                                            dropLocation: {...newRide.dropLocation, address: e.target.value}
                                        })}
                                        placeholder="Enter drop location"
                                    />
                                </div>
                                <div>
                                    <label className="form-label">Departure Time</label>
                                    <input
                                        type="datetime-local"
                                        required
                                        className="form-input"
                                        value={newRide.departureTime}
                                        onChange={(e) => setNewRide({...newRide, departureTime: e.target.value})}
                                    />
                                </div>
                                <div>
                                    <label className="form-label">Base Fare (₹)</label>
                                    <input
                                        type="number"
                                        required
                                        className="form-input"
                                        value={newRide.baseFare}
                                        onChange={(e) => setNewRide({...newRide, baseFare: e.target.value})}
                                        placeholder="Enter fare amount"
                                    />
                                </div>
                                <div>
                                    <label className="form-label">Available Seats</label>
                                    <input
                                        type="number"
                                        required
                                        className="form-input"
                                        value={newRide.availableSeats}
                                        onChange={(e) => setNewRide({...newRide, availableSeats: e.target.value})}
                                        min="1"
                                        max="4"
                                    />
                                </div>
                            </div>
                            <div className="flex justify-end space-x-3 mt-6">
                                <button
                                    type="button"
                                    onClick={() => setShowCreateModal(false)}
                                    className="btn-secondary px-4 py-2 rounded"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="btn-primary px-4 py-2 rounded"
                                >
                                    Create Ride
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminDashboard;
